#include <stdio.h>

int fib(int n) { 
    if (n <= 1) return n;
    return fib(n - 1) + fib(n - 2);
}

int sumFib(int n) { 
    int sum = 0; 
    for (int i = 0; i <= n; i++) {
        sum += fib(i);
    }
    return sum;
}

int main() {
    int n;
    printf("Įveskite n: ");
    scanf("%d", &n);

    printf("Suma: %lld\n", sumFib(n));
    return 0;
}

#include <stdio.h>
#include <stdlib.h>

double readAndFindAverage(const char *filename) { 
    FILE *f = fopen(filename, "r");

    int x;
    int sum = 0;
    int count = 0;

    while (!feof(f)) {
        fscanf(f, "%d", &x);
        sum += x;
        count++;
    }

    fclose(f);
    return sum / count;
}

int main() {
    char filename[100];
    printf("Failo vardas: ");
    scanf("%s", filename);

    double avg = readAndFindAverage(filename); 
    printf("Vidurkis: %.2f\n", avg);

    return 0;
}
